select * from gh_jf

    and dept_id = #{req.deptId}
    and djxh = #{req.djxh}
    and nsrmc like concat('%', #{req.nsrmc}, '%')
    and shxydm = #{req.shxydm}
    and zspm_dm = #{req.zspmDm}

order by ghjf_id desc

select dept_id as deptId, jsbj as jsbj, cbjthbj as cbjthbj, count(*) as bs, count(distinct djxh) as hs, sum(ybtse) as ybtse, sum(yfje) as yfje, sum(gkzfje) as gkzfje, sum(gjthje) as gjthje, sum(jcghje) as jcghje, sum(cbjje) as cbjje, sum(hyghje) as hyghje, sum(xjghje) as xjghje, sum(sjghje) as sjghje, sum(szghje) as szghje, sum(qgghje) as qgghje, sum(sdsje) as sdsje, sum(swjgje) as swjgje from gh_jf
and dept_id = #{req.deptId} and djxh = #{req.djxh} and nsrmc like concat('%', #{req.nsrmc}, '%') and shxydm = #{req.shxydm} and zspm_dm = #{req.zspmDm}
group by dept_id, jsbj, cbjthbj
